# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory backend for collaborative team work management.

Although the originating task narrative describes a health and fitness team
platform ("HealthTeamSync"), the concrete public contract exercised by the
accompanying test-suite is a generic *team collaboration* domain made up of
users, projects, tasks, messages, performance metrics and exportable reports.
This module implements that contract.

Design notes
------------
* **Single shared lock.** A single re-entrant lock (``threading.RLock``) guards
  every mutation and every read. The same lock object is shared (by identity)
  with each sub-store so that compound, cross-store operations remain atomic.
* **Monotonic global identifiers.** Every entity (user, project, task, message,
  rating) draws its id from one shared counter, so identifiers are unique across
  *all* entity types and start at ``1``.
* **Defensive copies.** Every value returned to a caller is a deep copy of the
  stored object. Mutating a returned object (or list) can never corrupt internal
  state.

The module depends only on the Python standard library.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Dict, List, Optional, Sequence, Set

__all__ = [
    "TeamCollaborationManager",
    "TaskStatus",
    "UserRole",
    "ReportFormat",
    "ReportType",
    "TeamCollaborationError",
    "ValidationError",
    "NotFoundError",
    "AuthorizationError",
    "DuplicateError",
    "ConflictError",
    "Attachment",
    "User",
    "Project",
    "Task",
    "Message",
    "Rating",
]


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Authorization role attached to a user."""

    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    """Supported export formats for generated reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """The kind of report produced by the manager."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by :class:`TeamCollaborationManager`."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails a validation rule."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """Metadata describing a file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    """A registered user of the platform."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A project (team workspace) owned by a user."""

    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    """A unit of work belonging to a project."""

    id: int
    project_id: int
    title: str
    description: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Message:
    """A message posted to either a project or a task thread."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment]
    created_at: datetime
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """A peer rating awarded from one user to another."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: Optional[str]
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Internal helpers
# ---------------------------------------------------------------------------
_UNSET = object()


def _clone(obj):
    """Return a deep copy so callers can never mutate stored state."""

    return copy.deepcopy(obj)


def _clone_list(objs):
    """Return a fresh list of deep copies."""

    return [copy.deepcopy(obj) for obj in objs]


# ---------------------------------------------------------------------------
# Sub-stores
#
# Each sub-store owns its own data structures but shares the manager's single
# re-entrant lock (by identity). Sub-store methods assume the lock is already
# held by the calling manager method; they never lock independently.
# ---------------------------------------------------------------------------
class _UserStore:
    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock
        self._users: Dict[int, User] = {}
        self._by_username: Dict[str, int] = {}
        self._by_email: Dict[str, int] = {}


class _ProjectStore:
    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock
        self._projects: Dict[int, Project] = {}


class _TaskStore:
    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock
        self._tasks: Dict[int, Task] = {}
        self._by_project: Dict[int, Set[int]] = {}
        self._by_assignee: Dict[int, Set[int]] = {}


class _MessageStore:
    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock
        self._messages: Dict[int, Message] = {}
        self._by_project: Dict[int, List[int]] = {}
        self._by_task: Dict[int, List[int]] = {}


class _PerformanceStore:
    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock
        self._ratings: Dict[int, Rating] = {}
        self._by_ratee: Dict[int, List[int]] = {}


class _ReportStore:
    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Coordinates users, projects, tasks, messaging, metrics and reports.

    Parameters
    ----------
    now:
        A zero-argument callable returning the "current" :class:`datetime`.
        Injecting a clock makes time-dependent behaviour deterministic for
        testing. Defaults to :func:`datetime.datetime.now`.
    """

    def __init__(self, now=None) -> None:
        self._lock = threading.RLock()
        self._now = now if now is not None else datetime.now
        self._id_counter = 0

        self.users = _UserStore(self._lock)
        self.projects = _ProjectStore(self._lock)
        self.tasks = _TaskStore(self._lock)
        self.messages = _MessageStore(self._lock)
        self.performance = _PerformanceStore(self._lock)
        self.reports = _ReportStore(self._lock)

    # -- id allocation ----------------------------------------------------
    def _next_id(self) -> int:
        """Return the next globally-unique id. Caller must hold ``_lock``."""

        self._id_counter += 1
        return self._id_counter

    # -- internal lookups (assume lock held, return live objects) ---------
    def _require_user(self, user_id: int) -> User:
        user = self.users._users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id: int) -> Project:
        project = self.projects._projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id: int) -> Task:
        task = self.tasks._tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id: int) -> Message:
        message = self.messages._messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    # ------------------------------------------------------------------ #
    # User management
    # ------------------------------------------------------------------ #
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            clean_name = self._validate_username(username)
            clean_email = self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if clean_name in self.users._by_username:
                raise DuplicateError("username already in use")
            if clean_email in self.users._by_email:
                raise DuplicateError("email already in use")

            user_id = self._next_id()
            user = User(
                id=user_id,
                username=clean_name,
                email=clean_email,
                role=role,
                created_at=self._now(),
            )
            self.users._users[user_id] = user
            self.users._by_username[clean_name] = user_id
            self.users._by_email[clean_email] = user_id
            return _clone(user)

    def get_user(self, user_id) -> User:
        with self._lock:
            return _clone(self._require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            ordered = [self.users._users[uid] for uid in sorted(self.users._users)]
            return _clone_list(ordered)

    def update_user(self, user_id, username=_UNSET, email=_UNSET, role=_UNSET) -> User:
        with self._lock:
            user = self._require_user(user_id)

            if username is not _UNSET:
                clean_name = self._validate_username(username)
                owner = self.users._by_username.get(clean_name)
                if owner is not None and owner != user_id:
                    raise DuplicateError("username already in use")
            if email is not _UNSET:
                clean_email = self._validate_email(email)
                owner = self.users._by_email.get(clean_email)
                if owner is not None and owner != user_id:
                    raise DuplicateError("email already in use")
            if role is not _UNSET and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not _UNSET:
                del self.users._by_username[user.username]
                user.username = clean_name
                self.users._by_username[clean_name] = user_id
            if email is not _UNSET:
                del self.users._by_email[user.email]
                user.email = clean_email
                self.users._by_email[clean_email] = user_id
            if role is not _UNSET:
                user.role = role
            return _clone(user)

    def delete_user(self, user_id) -> None:
        with self._lock:
            user = self._require_user(user_id)

            for project in self.projects._projects.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns one or more projects")

            for task_id in self.tasks._by_assignee.get(user_id, set()):
                task = self.tasks._tasks[task_id]
                if task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks assigned")

            # Detach any remaining (completed) tasks from the assignee index.
            for task_id in list(self.tasks._by_assignee.get(user_id, set())):
                self.tasks._tasks[task_id].assignee_id = None
            self.tasks._by_assignee.pop(user_id, None)

            del self.users._by_username[user.username]
            del self.users._by_email[user.email]
            del self.users._users[user_id]

    # -- user validation helpers -----------------------------------------
    @staticmethod
    def _validate_username(username) -> str:
        if not isinstance(username, str) or not username.strip():
            raise ValidationError("username must be a non-empty string")
        return username.strip()

    @staticmethod
    def _validate_email(email) -> str:
        if not isinstance(email, str):
            raise ValidationError("email must be a string")
        clean = email.strip()
        if not clean or "@" not in clean:
            raise ValidationError("email must be a non-empty address containing '@'")
        return clean

    # ------------------------------------------------------------------ #
    # Project management
    # ------------------------------------------------------------------ #
    def create_project(self, name, start_date, end_date, owner_id, description="") -> Project:
        with self._lock:
            clean_name = self._validate_name(name, "project name")
            self._validate_date_range(start_date, end_date)
            self._require_user(owner_id)

            project_id = self._next_id()
            project = Project(
                id=project_id,
                name=clean_name,
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self.projects._projects[project_id] = project
            return _clone(project)

    def get_project(self, project_id) -> Project:
        with self._lock:
            return _clone(self._require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            ordered = [
                self.projects._projects[pid]
                for pid in sorted(self.projects._projects)
            ]
            return _clone_list(ordered)

    def update_project(
        self,
        project_id,
        name=_UNSET,
        description=_UNSET,
        start_date=_UNSET,
        end_date=_UNSET,
    ) -> Project:
        with self._lock:
            project = self._require_project(project_id)

            if name is not _UNSET:
                clean_name = self._validate_name(name, "project name")
            new_start = project.start_date if start_date is _UNSET else start_date
            new_end = project.end_date if end_date is _UNSET else end_date
            if start_date is not _UNSET or end_date is not _UNSET:
                self._validate_date_range(new_start, new_end)

            if name is not _UNSET:
                project.name = clean_name
            if description is not _UNSET:
                project.description = description or ""
            if start_date is not _UNSET:
                project.start_date = start_date
            if end_date is not _UNSET:
                project.end_date = end_date
            return _clone(project)

    def delete_project(self, project_id) -> None:
        with self._lock:
            self._require_project(project_id)

            task_ids = list(self.tasks._by_project.get(project_id, set()))
            for task_id in task_ids:
                task = self.tasks._tasks.pop(task_id, None)
                if task is None:
                    continue
                if task.assignee_id is not None:
                    assignee_tasks = self.tasks._by_assignee.get(task.assignee_id)
                    if assignee_tasks is not None:
                        assignee_tasks.discard(task_id)
                        if not assignee_tasks:
                            del self.tasks._by_assignee[task.assignee_id]
                # Drop any messages attached to the task being removed.
                for message_id in self.messages._by_task.pop(task_id, []):
                    self.messages._messages.pop(message_id, None)
            self.tasks._by_project.pop(project_id, None)

            for message_id in self.messages._by_project.pop(project_id, []):
                self.messages._messages.pop(message_id, None)

            del self.projects._projects[project_id]

    # -- project validation helpers --------------------------------------
    @staticmethod
    def _validate_name(name, label) -> str:
        if not isinstance(name, str) or not name.strip():
            raise ValidationError("{0} must be a non-empty string".format(label))
        return name.strip()

    @staticmethod
    def _validate_date_range(start_date, end_date) -> None:
        if start_date is None or end_date is None:
            raise ValidationError("start_date and end_date are required")
        if end_date < start_date:
            raise ValidationError("end_date cannot be before start_date")

    # ------------------------------------------------------------------ #
    # Task management
    # ------------------------------------------------------------------ #
    def create_task(
        self, project_id, title, description="", assignee_id=None, deadline=None
    ) -> Task:
        with self._lock:
            project = self._require_project(project_id)
            clean_title = self._validate_name(title, "task title")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede the project start")

            task_id = self._next_id()
            task = Task(
                id=task_id,
                project_id=project_id,
                title=clean_title,
                description=description or "",
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._now(),
            )
            self.tasks._tasks[task_id] = task
            self.tasks._by_project.setdefault(project_id, set()).add(task_id)
            if assignee_id is not None:
                self.tasks._by_assignee.setdefault(assignee_id, set()).add(task_id)
            return _clone(task)

    def get_task(self, task_id) -> Task:
        with self._lock:
            return _clone(self._require_task(task_id))

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self.tasks._by_project.get(project_id, set()))
            return _clone_list([self.tasks._tasks[tid] for tid in ids])

    def list_tasks_by_assignee(self, assignee_id) -> List[Task]:
        with self._lock:
            self._require_user(assignee_id)
            ids = sorted(self.tasks._by_assignee.get(assignee_id, set()))
            return _clone_list([self.tasks._tasks[tid] for tid in ids])

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return _clone(task)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return _clone(task)

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._set_assignee(task, None)
            return _clone(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self._require_project(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError("deadline cannot precede the project start")
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return _clone(task)

    def _set_assignee(self, task: Task, new_assignee: Optional[int]) -> None:
        """Move ``task`` between assignee indexes. Caller must hold ``_lock``."""

        old = task.assignee_id
        if old is not None:
            old_set = self.tasks._by_assignee.get(old)
            if old_set is not None:
                old_set.discard(task.id)
                if not old_set:
                    del self.tasks._by_assignee[old]
        task.assignee_id = new_assignee
        if new_assignee is not None:
            self.tasks._by_assignee.setdefault(new_assignee, set()).add(task.id)

    # ------------------------------------------------------------------ #
    # Messaging
    # ------------------------------------------------------------------ #
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ) -> Message:
        with self._lock:
            self._require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id must be provided"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            now = self._now()
            built: List[Attachment] = []
            for filename, data in attachments or []:
                built.append(self._build_attachment(filename, data, author_id, now))

            if (body is None or not str(body).strip()) and not built:
                raise ValidationError("message requires a body or an attachment")

            message_id = self._next_id()
            message = Message(
                id=message_id,
                author_id=author_id,
                body=body if body is not None else "",
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built,
                created_at=now,
                edited_at=None,
            )
            self.messages._messages[message_id] = message
            if project_id is not None:
                self.messages._by_project.setdefault(project_id, []).append(message_id)
            else:
                self.messages._by_task.setdefault(task_id, []).append(message_id)
            return _clone(message)

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            if (new_body is None or not str(new_body).strip()) and not message.attachments:
                raise ValidationError("message requires a body or an attachment")
            message.body = new_body if new_body is not None else ""
            message.edited_at = self._now()
            return _clone(message)

    def add_attachment(self, message_id, uploader_id, filename, data) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError("only the author may attach to a message")
            attachment = self._build_attachment(
                filename, data, uploader_id, self._now()
            )
            message.attachments.append(attachment)
            return _clone(message)

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self.messages._by_project.get(project_id, []))
            return _clone_list([self.messages._messages[mid] for mid in ids])

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            ids = sorted(self.messages._by_task.get(task_id, []))
            return _clone_list([self.messages._messages[mid] for mid in ids])

    def delete_message(self, message_id, requester_id) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete a message")
            if message.project_id is not None:
                bucket = self.messages._by_project.get(message.project_id)
                if bucket is not None and message_id in bucket:
                    bucket.remove(message_id)
            if message.task_id is not None:
                bucket = self.messages._by_task.get(message.task_id)
                if bucket is not None and message_id in bucket:
                    bucket.remove(message_id)
            del self.messages._messages[message_id]

    @staticmethod
    def _build_attachment(filename, data, uploaded_by, when) -> Attachment:
        if not isinstance(filename, str) or not filename.strip():
            raise ValidationError("attachment filename must be a non-empty string")
        try:
            size = len(data)
        except TypeError:
            raise ValidationError("attachment data must be sized (bytes-like)")
        return Attachment(
            filename=filename,
            size=size,
            uploaded_by=uploaded_by,
            uploaded_at=when,
        )

    # ------------------------------------------------------------------ #
    # Performance metrics
    # ------------------------------------------------------------------ #
    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._require_user(user_id)
            return self._completion_rate(user_id)

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            return self._average_completion_time(user_id)

    def submit_rating(self, rater_id, ratee_id, score, feedback=None, task_id=None) -> Rating:
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            if isinstance(score, bool) or not isinstance(score, int):
                raise ValidationError("score must be an integer between 1 and 5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._require_task(task_id)

            rating_id = self._next_id()
            rating = Rating(
                id=rating_id,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback,
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance._ratings[rating_id] = rating
            self.performance._by_ratee.setdefault(ratee_id, []).append(rating_id)
            return _clone(rating)

    def get_ratings_summary(self, user_id) -> dict:
        with self._lock:
            self._require_user(user_id)
            rating_ids = self.performance._by_ratee.get(user_id, [])
            ratings = [self.performance._ratings[rid] for rid in rating_ids]
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {
                "user_id": user_id,
                "count": count,
                "average": average,
                "ratings": _clone_list(ratings),
            }

    def get_user_dashboard(self, user_id) -> dict:
        with self._lock:
            self._require_user(user_id)
            task_ids = self.tasks._by_assignee.get(user_id, set())
            tasks = [self.tasks._tasks[tid] for tid in task_ids]

            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)

            rating_ids = self.performance._by_ratee.get(user_id, [])
            rating_count = len(rating_ids)
            rating_average = (
                sum(self.performance._ratings[rid].score for rid in rating_ids)
                / rating_count
                if rating_count
                else 0.0
            )

            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": self._average_completion_time(user_id),
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # -- performance helpers (assume lock held) --------------------------
    def _completion_rate(self, user_id: int) -> float:
        task_ids = self.tasks._by_assignee.get(user_id, set())
        total = len(task_ids)
        if not total:
            return 0.0
        completed = sum(
            1
            for tid in task_ids
            if self.tasks._tasks[tid].status == TaskStatus.COMPLETED
        )
        return completed / total

    def _average_completion_time(self, user_id: int) -> Optional[float]:
        durations = []
        for tid in self.tasks._by_assignee.get(user_id, set()):
            task = self.tasks._tasks[tid]
            if (
                task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append((task.completed_at - task.started_at).total_seconds())
        if not durations:
            return None
        return sum(durations) / len(durations)

    # ------------------------------------------------------------------ #
    # Reports
    # ------------------------------------------------------------------ #
    def project_progress_report(self, project_id) -> dict:
        with self._lock:
            self._require_project(project_id)
            task_ids = self.tasks._by_project.get(project_id, set())
            tasks = [self.tasks._tasks[tid] for tid in task_ids]

            now = self._now()
            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            completed = 0
            per_assignee: Dict[int, dict] = {}

            for task in tasks:
                status_counts[task.status.value] += 1
                if task.status == TaskStatus.COMPLETED:
                    completed += 1
                if (
                    task.deadline is not None
                    and task.status != TaskStatus.COMPLETED
                    and task.deadline < now
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id,
                        {"total_tasks": 0, "completed_tasks": 0, "completion_rate": 0.0},
                    )
                    bucket["total_tasks"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed_tasks"] += 1

            for bucket in per_assignee.values():
                bucket["completion_rate"] = (
                    bucket["completed_tasks"] / bucket["total_tasks"]
                    if bucket["total_tasks"]
                    else 0.0
                )

            total = len(tasks)
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None) -> dict:
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                scoped_ids = self.tasks._by_project.get(project_id, set())
            else:
                scoped_ids = set(self.tasks._tasks.keys())

            grouped: Dict[int, List[Task]] = {}
            for tid in scoped_ids:
                task = self.tasks._tasks[tid]
                if task.assignee_id is None:
                    continue
                grouped.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(grouped):
                rows.append(self._performance_row(user_id, grouped[user_id]))

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id) -> dict:
        with self._lock:
            self._require_user(user_id)
            task_ids = sorted(self.tasks._by_assignee.get(user_id, set()))
            tasks = [self.tasks._tasks[tid] for tid in task_ids]

            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)

            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": len(tasks),
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": self._completion_rate(user_id),
                "average_completion_time": self._average_completion_time(user_id),
                "tasks": [self._task_summary(t) for t in tasks],
            }

    def export_report(self, report, report_format) -> object:
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a report dictionary")
            if not isinstance(report_format, ReportFormat):
                raise ValidationError("report_format must be a ReportFormat")
            if report_format == ReportFormat.CSV:
                return self._report_to_csv(report)
            if report_format == ReportFormat.PDF:
                return self._report_to_pdf(report)
            raise ValidationError("unsupported report format")

    # -- report helpers (assume lock held) -------------------------------
    def _performance_row(self, user_id: int, tasks: Sequence[Task]) -> dict:
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ]
        average_time = sum(durations) / len(durations) if durations else None
        user = self.users._users.get(user_id)
        return {
            "user_id": user_id,
            "username": user.username if user is not None else "",
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": (completed / total) if total else 0.0,
            "average_completion_time": average_time,
        }

    @staticmethod
    def _task_summary(task: Task) -> dict:
        return {
            "task_id": task.id,
            "title": task.title,
            "status": task.status.value,
            "assignee_id": task.assignee_id,
            "deadline": task.deadline.isoformat() if task.deadline else None,
        }

    @staticmethod
    def _stringify(value) -> str:
        if value is None:
            return ""
        if isinstance(value, dict):
            return "; ".join(
                "{0}={1}".format(key, val) for key, val in value.items()
            )
        if isinstance(value, (list, tuple)):
            return "{0} items".format(len(value))
        return str(value)

    def _report_to_csv(self, report: dict) -> str:
        output = io.StringIO()
        writer = csv.writer(output)

        rows = report.get("rows")
        if isinstance(rows, list) and rows and all(isinstance(r, dict) for r in rows):
            headers: List[str] = []
            for row in rows:
                for key in row:
                    if key not in headers:
                        headers.append(key)
            writer.writerow(headers)
            for row in rows:
                writer.writerow([self._stringify(row.get(h)) for h in headers])
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([key, self._stringify(value)])
        return output.getvalue()

    def _report_to_pdf(self, report: dict) -> bytes:
        lines: List[str] = []
        report_type = report.get("report_type", "report")
        lines.append("Report: {0}".format(report_type))
        for key, value in report.items():
            if key == "report_type":
                continue
            if isinstance(value, dict):
                lines.append("{0}:".format(key))
                for sub_key, sub_value in value.items():
                    lines.append("  {0}: {1}".format(sub_key, self._stringify(sub_value)))
            elif isinstance(value, (list, tuple)):
                lines.append("{0}: {1} item(s)".format(key, len(value)))
            else:
                lines.append("{0}: {1}".format(key, self._stringify(value)))
        return _build_pdf(lines)


# ---------------------------------------------------------------------------
# Minimal, dependency-free PDF writer
# ---------------------------------------------------------------------------
def _escape_pdf_text(text: str) -> str:
    return (
        text.replace("\\", "\\\\")
        .replace("(", "\\(")
        .replace(")", "\\)")
        .replace("\r", " ")
        .replace("\n", " ")
    )


def _build_pdf(lines: Sequence[str]) -> bytes:
    """Build a minimal but structurally valid single-page PDF document."""

    if not lines:
        lines = [""]

    text_ops = ["BT", "/F1 12 Tf", "50 750 Td"]
    for index, line in enumerate(lines):
        if index > 0:
            text_ops.append("0 -16 Td")
        text_ops.append("({0}) Tj".format(_escape_pdf_text(line)))
    text_ops.append("ET")
    stream = "\n".join(text_ops)
    stream_bytes = stream.encode("latin-1", "replace")

    objects = [
        "<< /Type /Catalog /Pages 2 0 R >>",
        "<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            "<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            "/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
        ),
        "<< /Length {0} >>\nstream\n{1}\nendstream".format(len(stream_bytes), stream),
        "<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    buffer = bytearray(b"%PDF-1.4\n")
    offsets: List[int] = []
    for number, body in enumerate(objects, start=1):
        offsets.append(len(buffer))
        buffer.extend(
            "{0} 0 obj\n{1}\nendobj\n".format(number, body).encode("latin-1", "replace")
        )

    xref_offset = len(buffer)
    count = len(objects) + 1
    buffer.extend("xref\n0 {0}\n".format(count).encode("latin-1"))
    buffer.extend(b"0000000000 65535 f \n")
    for offset in offsets:
        buffer.extend("{0:010d} 00000 n \n".format(offset).encode("latin-1"))
    buffer.extend(
        (
            "trailer\n<< /Size {0} /Root 1 0 R >>\nstartxref\n{1}\n%%EOF\n".format(
                count, xref_offset
            )
        ).encode("latin-1")
    )
    return bytes(buffer)
